-- PharmaConnect Drug Catalog Seed
-- Generated from WHO EML 23rd edition (2023) + Nigerian brand cross-reference
-- DELETE FROM pharmacy_stock WHERE is_seed_data = 1; to clean on launch

CREATE TABLE IF NOT EXISTS drugs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  drug_name TEXT NOT NULL,
  category TEXT,
  dosage_form TEXT,
  price_range TEXT,
  brand_names TEXT,
  is_common INTEGER DEFAULT 1,
  is_seed_data INTEGER DEFAULT 1
);

CREATE TABLE IF NOT EXISTS pharmacy_stock (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  pharmacy_id INTEGER NOT NULL,
  drug_id INTEGER NOT NULL,
  stock_quantity INTEGER DEFAULT 0,
  status TEXT DEFAULT "In Stock",
  is_seed_data INTEGER DEFAULT 1
);


